from fastapi import FastAPI, Depends, Header, HTTPException, status
from typing import Optional

app = FastAPI()

# In a real application, this would come from environment variables or a secure configuration system.
# For demonstration purposes, we're hardcoding it.
API_KEY = "your-super-secret-api-key"

async def verify_api_key(x_api_key: str = Header(...)):
    if x_api_key != API_KEY:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid API Key",
        )
    return x_api_key

@app.get("/")
async def read_root():
    return {"message": "Welcome to the unprotected root!"}

@app.get("/protected-data/", dependencies=[Depends(verify_api_key)])
async def get_protected_data():
    return {"message": "This data is protected!", "data": [1, 2, 3, 4, 5]}

# Example of using the API key value within the endpoint if needed
@app.get("/user-profile/", dependencies=[Depends(verify_api_key)])
async def get_user_profile(api_key: str = Depends(verify_api_key)):
    # Here, 'api_key' will contain the validated API key string
    # In a real app, you might use this to look up user roles or specific permissions
    return {"message": "User profile data", "api_key_used": api_key, "user": "authorized_user"}

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)
